Material.Shader:
/* This is a vertex program for ...
 */

varying vec3 normal;
varying float scalar;

void main()
{
  /* Transform the normal. */
  normal = normalize(gl_NormalMatrix*gl_Normal);
  scalar = gl_Normal * normal ;

  gl_Position = ftransform();
}

/* This is a fragment program ...
 */
varying float scalar;

void main()
{
	scalar = 6.0 * (scalar + 1.0);
	int parity = scalar;
	parity = parity % 2;
	if(parity == 1)
		gl_FragColor = vec4(1.0, 1.0, 1.0, 1.0);
	else
		gl_FragColor = vec4(0.0, 0.0, 0.0, 1.0);
}
